import React, { useState, ChangeEvent, FormEvent } from 'react';
import { LoginFormData, LoginFormErrors, LoginPayload } from '../types/login.types';
import './LoginPage.css';

const LoginPage: React.FC = () => {
  const [formData, setFormData] = useState<LoginFormData>({
    email: '',
    password: '',
    rememberMe: false,
  });

  const [errors, setErrors] = useState<LoginFormErrors>({});
  const [isLoading, setIsLoading] = useState<boolean>(false);

  const validate = (): boolean => {
    const newErrors: LoginFormErrors = {};
    if (!formData.email) {
      newErrors.email = 'Email is required';
    } else if (!/\S+@\S+\.\S+/.test(formData.email)) {
      newErrors.email = 'Invalid email format';
    }
    if (!formData.password) {
      newErrors.password = 'Password is required';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleChange = (e: ChangeEvent<HTMLInputElement>): void => {
    const { name, value, type, checked } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));
    setErrors((prev) => ({ ...prev, [name]: undefined }));
  };

  const handleSubmit = async (e: FormEvent<HTMLFormElement>): Promise<void> => {
    e.preventDefault();
    if (!validate()) return;

    setIsLoading(true);

    const payload: LoginPayload = {
      email: formData.email,
      password: formData.password,
      rememberMe: formData.rememberMe,
    };

    try {
      // Replace with your actual API endpoint
      const response = await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      if (!response.ok) throw new Error('Login failed');

      const data = await response.json();
      console.log('Login success:', data);
      // TODO: redirect or store token here
    } catch (error) {
      console.error('Login error:', error);
      setErrors({ password: 'Invalid email or password' });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="login-page">
      <div className="login-bg-image" />

      <div className="login-form-wrapper">
        <form className="login-form-group" onSubmit={handleSubmit} noValidate>

          <h1 className="login-title">Welcome back!</h1>
          <p className="login-subtitle">Enter your Credentials to access your account</p>

          {/* Email Field */}
          <div className="field-email">
            <label className="field-label">Email address</label>
            <input
              className="field-input"
              type="email"
              name="email"
              placeholder="Enter your email"
              value={formData.email}
              onChange={handleChange}
            />
            {errors.email && <span className="error-message">{errors.email}</span>}
          </div>

          {/* Password Field */}
          <div className="field-password">
            <label className="field-label">Password</label>
            <input
              className="field-input"
              type="password"
              name="password"
              placeholder="Enter your password"
              value={formData.password}
              onChange={handleChange}
            />
            {errors.password && <span className="error-message">{errors.password}</span>}
          </div>

          {/* Forgot Password */}
          <a href="/forgot-password" className="forgot-password">Forgot password</a>

          {/* Remember Me */}
          <div className="remember-me-group">
            <input
              className="remember-me-checkbox"
              type="checkbox"
              name="rememberMe"
              id="rememberMe"
              checked={formData.rememberMe}
              onChange={handleChange}
            />
            <label className="remember-me-label" htmlFor="rememberMe">Remember me</label>
          </div>

          {/* Login Button */}
          <div className="login-btn-wrapper">
            <button className="login-btn" type="submit" disabled={isLoading}>
              <span className="login-btn-text">{isLoading ? 'Logging in...' : 'Login'}</span>
            </button>
          </div>

        </form>
      </div>

      {/* Sign Up Link */}
      <p className="signup-link">
        Don't have an account? <span onClick={() => window.location.href = '/signup'}>Sign Up</span>
      </p>
    </div>
  );
};

export default LoginPage;
